import React, { FC, useState } from 'react'
import { Chip, Divider, Stack, styled, Typography } from '@mui/material'
import { PieChart, useDrawingArea } from '@mui/x-charts'
import { MetaStorage } from '../helpers/MetaStorage'

import './toolbar.css'
import { Lock } from '@mui/icons-material'
import Tooltip, { tooltipClasses, TooltipProps } from '@mui/material/Tooltip'
import { LocalStorage } from '../helpers/LocalStorage'

interface SerpProps {
  url: string,
  configData: any,
  toolbarData?: any
}

/**
 * Command visibility level
 */
enum VisibilityLevel {
  None = 'none',
  Community = 'community',
  Pro = 'pro'
}

const Serp: FC<SerpProps> = (props: SerpProps) => {
  const [toolbarData, updateToolbarData] = useState<any>(props.toolbarData)
  const [configData, updateConfigData] = useState<any>(props.configData)
  const [darkMode, updateDarkMode] = useState(props.configData.theme)
  const ls = new LocalStorage()

  /**
   * Main event cycle
   */
  ls.storage().onChanged.addListener((changes, namespace) => {
    for (let [key, { oldValue, newValue }] of Object.entries(changes)) {
      switch(key) {
        case 'config':
          updateConfigData(newValue)
          updateDarkMode(newValue?.theme)
          break
      }
    }
  })

  /**
   * Get toolbar visibility level
   */
  const visibility = (): VisibilityLevel => {
    if (!configData || !configData.token) {
      return VisibilityLevel.None
    }
    if (!configData.is_pro) {
      return VisibilityLevel.Community
    }
    return VisibilityLevel.Pro
  }

  /**
   * Tooltip component
   */
  const BootstrapTooltip = styled(({ className, ...props }: TooltipProps) => (
    <Tooltip {...props} arrow classes={{ popper: className }} />
  ))(({ theme }) => ({
    [`& .${tooltipClasses.arrow}`]: {
      color: "#616161E5",
    },
    [`& .${tooltipClasses.tooltip}`]: {
      backgroundColor: "#616161E5",
      color: "#ffffff",
      fontSize: "12px"
    },
  }))


  /**
   * Blur specified text
   * @param text
   */
  const blurText = (text: string) => {
    return (
      <div style={{ filter: 'blur(8px)', pointerEvents: 'none', color: 'var(--text-main)' }}>
        lorem
      </div>
    )
  }

  /**
   * Build pie diagram
   * @param size
   * @param value
   */
  const buildPie = (size: number, value: number | null, url?: string) => {
    const sizeInner = size - 9
    const angle = value ?? 0

    // Depending on theme switch pie color
    let color = '#0077BB'
    if (darkMode) color = '#4DBEEB'

    const StyledText = styled('text')(({ theme }) => ({
      fill: 'var(--text-main)',
      textAnchor: 'middle',
      dominantBaseline: 'central',
      fontSize: 14,
      color: 'var(--text-main)'
    }));

    function PieCenterLabel({ children }: { children: React.ReactNode }) {
      const { height, top } = useDrawingArea();
      return (
        <StyledText x={size + 5} y={top + height / 2} className={"moztoolbar-highlight"} style={children as number>=100 ? {fontSize: "12px"} : {}}>
          {children}
        </StyledText>
      );
    }

    return (
      <span className={"moztoolbar-cursor moztoolbar-highlight"} onClick={(ev) => meta.openContentLink(url ? url : '')}>
        <PieChart
          series={[
            {
              data: [
                { value: angle, color: color },
                { value: 100 - angle, color: darkMode ? '#092A46' : '#BBB' },
              ],
              innerRadius: sizeInner,
              outerRadius: size,
              paddingAngle: 0,
              cx: size,
              cy: size,
            }
          ]}
          width={size*2 + 10}
          height={size*2 + 10}
          slotProps={{
            legend: { hidden: true },
          }}
          tooltip={{trigger: 'none'}}
        >
          <PieCenterLabel>{angle ? angle : '-'}</PieCenterLabel>
        </PieChart>
      </span>
    )
  }


  /**
   * Main template
   */
  const meta = new MetaStorage()
  // Show regular toolbar
  return (
    <div className={[darkMode ? 'theme-dark' : 'theme-light', 'mozbar-serp-overlay'].join(' ')}>
      <Stack spacing={2} direction="row" justifyItems={"flex-start"} className={"moztoolbar-toolbar"}>
        <Stack alignItems="center" direction="row" spacing={1} justifyContent={'flex-start'} justifyItems={"center"}>
          <div>
            <Stack alignItems="center" direction="row" spacing={1}>
              <BootstrapTooltip placement={"bottom"} title={meta.domainAuthorityTooltip}>
                <div>
                  <h2 className="mozbar-serp-overlay-header">Domain</h2>
                  <Typography className={'mozbar-serp-overlay-p'}>Authority</Typography>
                </div>
              </BootstrapTooltip>
              {visibility() !== VisibilityLevel.None ? buildPie(20, toolbarData?.domain_authority, meta.buildMetricsLink(props.url, 'domain')) : <></>}
            </Stack>
          </div>

          <Divider variant={"middle"} orientation={"vertical"}/>
          <div>
            <BootstrapTooltip title={meta.linkingDomainsTooltip} placement={"bottom"}>
              <h2 className="mozbar-serp-overlay-header moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(props.url, 'domain'))}>{meta.numberFormat(toolbarData?.da?.ld, true)}</span>) : blurText('')}</h2>
            </BootstrapTooltip>
            <Typography className={'mozbar-serp-overlay-p'}>
              Domains
            </Typography>
          </div>
          <Divider variant={"middle"} orientation={"vertical"}/>
          <div>
            <BootstrapTooltip title={meta.inboundLinksTooltip} placement={"bottom"}>
              <h2 className="mozbar-serp-overlay-header moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(props.url, 'domain'))}>{meta.numberFormat(toolbarData?.da?.lp, true)}</span>) : blurText('')}</h2>
            </BootstrapTooltip>
            <Typography className={'mozbar-serp-overlay-p'}>
              Links
            </Typography>
          </div>

          <div style={{marginLeft: "15px"}}>
            <Stack alignItems="center" direction="row" spacing={1}>
              <BootstrapTooltip placement={"bottom"} title={meta.pageAuhorityTooltip}>
                <div>
                  <h2 className="mozbar-serp-overlay-header">Page</h2>
                  <Typography className={'mozbar-serp-overlay-p'}>Authority</Typography>
                </div>
              </BootstrapTooltip>
              {visibility() !== VisibilityLevel.None ? buildPie(20, toolbarData?.page_authority, meta.buildMetricsLink(props.url, 'page')) : <></>}
            </Stack>
          </div>
          <Divider variant={'middle'} orientation={'vertical'}/>
          <div>
            <BootstrapTooltip title={meta.linkingDomainsTooltip} placement={"bottom"}>
              <h2 className="mozbar-serp-overlay-header moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(props.url, 'page'))}>{meta.numberFormat(toolbarData?.pa?.ld, true)}</span>) : blurText('')}</h2>
            </BootstrapTooltip>
            <Typography className={'mozbar-serp-overlay-p'}>
              Domains
            </Typography>
          </div>
          <Divider variant={'middle'} orientation={'vertical'}/>
          <div>
            <BootstrapTooltip title={meta.inboundLinksTooltip} placement={"bottom"}>
              <h2 className="mozbar-serp-overlay-header moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(props.url, 'page'))}>{meta.numberFormat(toolbarData?.pa?.lp, true)}</span>) : blurText('')}</h2>
            </BootstrapTooltip>
            <Typography className={'mozbar-serp-overlay-p'}>
              Links
            </Typography>
          </div>

          {visibility() === VisibilityLevel.None && (
            <div
              onClick={ev => meta.openContentLink(meta.serp_link_new_account)}>
              <Stack alignItems="center" direction="row" spacing={1}>
                <Chip className={'moztoolbar-cursor'} label="Login or Create Account"
                      icon={<Lock style={{ fontSize: '20px', color: '#000000', paddingLeft: '4px' }}/>}
                      sx={{ borderRadius: '15px', color: '#000000', fontSize: '13px', background: '#FFD05F' }}/>
              </Stack>
            </div>
          )}
          {visibility() === VisibilityLevel.Community && (
            <div
              onClick={ev => meta.openContentLink(meta.serp_link_upgrade)}>
              <Stack alignItems="center" direction="row" spacing={1}>
                <Chip className={'moztoolbar-cursor'} label="Premium"
                      icon={<Lock style={{ fontSize: '20px', color: '#000000', paddingLeft: '4px' }}/>}
                      sx={{ borderRadius: '15px', color: '#000000', fontSize: '13px', background: '#FFD05F' }}/>
              </Stack>
            </div>
          )}
        </Stack>
      </Stack>
    </div>
  )
}

export default Serp;