import { EventStorage } from '../helpers/EventStorage'
// jQuery stuff required for highlighting
import mozbarquery from 'jquery'
import 'jquery-highlight'
import { BrowserApi } from './api'
import { MetaStorage } from '../helpers/MetaStorage'
import { LocalStorage } from '../helpers/LocalStorage'

declare var global: any;
global.jQuery = mozbarquery;

const browser = new BrowserApi()

if (document.readyState === 'complete') {
  startCollect();
} else {
  window.addEventListener('load', startCollect);
}

function startCollect() {
  const event = new EventStorage()
  const timing = performance.getEntriesByType('navigation')[0].toJSON()
  timing.start = performance.timing.requestStart
  // delete timing.serverTiming;
  if (timing.duration > 0) {
    // fetchStart sometimes negative in FF, make an adjustment based on fetchStart
    const adjustment = timing.fetchStart < 0 ? -timing.fetchStart : 0;
    [
      'domainLookupStart',
      'domainLookupEnd',
      'connectStart',
      'connectEnd',
      'requestStart',
      'responseStart',
      'responseEnd',
      'domComplete',
      'domInteractive',
      'domContentLoadedEventStart',
      'domContentLoadedEventEnd',
      'loadEventStart',
      'loadEventEnd',
      'duration'
    ].forEach(i => {
      timing[i] +=adjustment
    })

    // we have only 4 chars in our disposal including decimal point (3 in Firefox 92+)
    const isFF = navigator.userAgent.indexOf("Firefox") > -1
    const duration = timing.duration / 1000
    let precision = (duration >= 100) ? 0 : (duration >= 10 ? 1 : 2)
    if (isFF) {
      precision = Math.max(0, precision - 1)
    }
    const time = duration.toFixed(precision).substring(0, isFF ? 3 : 4)
    event.sendMessage({type: event.SOURCE_BACKGROUND, from: event.SOURCE_CONTENT, message: 'pageinfo-time', time: time, timing: timing})
  } else {
    setTimeout(startCollect, 100)
  }
}

/**
 * Handle incoming messages
 */
const ls = new LocalStorage()
chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  const event = new EventStorage()
  if (request.type === event.SOURCE_CONTENT) {
    switch (request.message) {
      /**
       * Toolbar functions
       */
      case 'show.toolbar':
        // Show toolbar
        browser.showToolbar()
        break
      case 'hide.toolbar':
        // Hide toolbar
        browser.hideToolbar()
        break

      /**
       * DA mode functions
       */
      case 'show.da_mode':
        const da = request.data
        const canvas = browser.createDAIcon(da, 15, 15)
        const imageData = canvas?.getContext('2d')?.getImageData(0, 0, 15, 15)
        event.sendMessage(event.buildMessage(event.SOURCE_BACKGROUND, event.SOURCE_CONTENT, "set-icon", imageData?.data))
        break
      case 'hide.da_mode':
        event.sendMessage(event.buildMessage(event.SOURCE_BACKGROUND, event.SOURCE_CONTENT, "set-icon", {}))
        break

      /**
       * SERP events
       */
      case 'show.serp':
      case 'show.places':
        // Show SERP bars
        browser.showSERP()
        break
      case 'hide.serp':
      case 'hide.places':
      case 'refresh.serp':
        // Refresh SERP bars and make sure it displays active data
        browser.hideSERP()
        browser.showSERP()
        break
      case 'serp':
        // Display SERP bars for SE page
        browser.displaySERPbars(request)
        break
      case 'serp-export':
        // Export SERP data to CSV
        browser.exportSERPdata(request)
        break


      /**
       * Extension highlight function
       */
      case 'highlight':
        browser.highlight(request?.data?.type, request?.data)
        break

      /**
       * Calculate number of words on the page
       */
      case 'countwords':
        const count = browser.countwords(request?.data?.keyword)
        event.sendMessage({
          type: event.SOURCE_EXTENSION,
          from: event.SOURCE_CONTENT,
          message: "countwords",
          count: count,
        });
        break

      /**
       * Request coming from background script once moz.com/status page is opened
       * Page content should be read and session.id is forwarded to the extension
       */
      case 'login':
        const data = document.body.innerText
        try {
          const json = JSON.parse(data)
          if (json) {
            const sessionId = json.session.id
            event.sendMessage(event.buildMessage(event.SOURCE_BACKGROUND, event.SOURCE_CONTENT, 'login-response', sessionId))
              .then((res) => {
                window.close()
              }, (err) => {
                console.log('Close err: ', err)
              })
          }
        }
        catch(err) {
          console.log('Login err: ', err)
        }
        break

      /**
       * Update DA icon
       */
      case 'status':
        ls.get('config').then((res: any) => {
          if (!request?.data?.domain_authority || !res.da_mode) {
            event.sendMessage(event.buildMessage(event.SOURCE_BACKGROUND, event.SOURCE_CONTENT, "set-icon", {}))
          } else {
            const da = request?.data?.domain_authority
            const canvas = browser.createDAIcon(da, 15, 15)
            const imageData = canvas?.getContext('2d')?.getImageData(0, 0, 15, 15)
            event.sendMessage(event.buildMessage(event.SOURCE_BACKGROUND, event.SOURCE_CONTENT, "set-icon", imageData?.data))
          }
        })
        break

      /**
       * Main entry point to refresh page based on config data coming from extension
       */
      case 'config':
        // Rest of config
        if (request.data.toolbar === true) {
          browser.showToolbar()
        } else {
          browser.hideToolbar()
        }
        if (request.data.serp === true) {
          browser.showSERP()
        } else {
          browser.hideSERP()
          browser.showSERP()
        }
        if (request.data.followed === true) {
          browser.highlight('followed', {value: true})
        } else {
          browser.highlight('followed', {value: false})
        }
        if (request.data.nofollow === true) {
          browser.highlight('nofollow', {value: true})
        } else {
          browser.highlight('nofollow', {value: false})
        }
        if (request.data.external === true) {
          browser.highlight('external', {value: true})
        } else {
          browser.highlight('external', {value: false})
        }
        if (request.data.internal === true) {
          browser.highlight('internal', {value: true})
        } else {
          browser.highlight('internal', {value: false})
        }
        if (request.data.keywordhighlight === true) {
          browser.highlight('keyword', {value: true, keyword: request.data.keyword})
        } else {
          browser.highlight('keyword', {value: false, keyword: request.data.keyword})
        }
        break

      /**
       * Get structure JSON+LD data
       */
      case 'schema':
        const schema = browser.tag('script[type="application/ld+json"]', [])
        schema.forEach((item, index) => {
          let data = []
          try {
            data = JSON.parse(item)
          }
          catch(e) {
          }
          event.sendMessage(event.buildMessage(event.SOURCE_EXTENSION, event.SOURCE_CONTENT, "schema", data));
        })
        break

      /**
       * Get page basic layout information
       */
      case 'pageinfo':
        const keywords = browser.tag('meta[name=keywords]', ['content'])
        const description = browser.tag('meta[name=description]', ['content'])
        const robots = browser.tag('meta[name=robots]', ['content'])
        const h1 = browser.tag('h1', [])
        const h2 = browser.tag('h2', [])
        const img = browser.tag('img', ['alt'])
        const canonical = browser.tag('link[rel="canonical"]', ['href'])
        const hreflangs = browser.tag('link[rel="alternate"]', ['hreflang', 'href'])
        const url = 'https://' + window.location.host
        browser.robots(url).then((res) => {
          const robotsData = res?.data?.split('\n')?.length > 0 ? res?.data?.split('\n') : []
          const sitemaps: string[] = []
          if (robotsData) {
            robotsData.forEach((item: string) => {
              const pos = item.search(/sitemap:/gi)
              if (pos>=0) {
                const sitemap = item.substring(pos + 8, item.length).trim()
                sitemaps.push(sitemap)
              }
            })
          }
          event.sendMessage({
            type: event.SOURCE_EXTENSION,
            from: event.SOURCE_CONTENT,
            message: "pageinfo",
            keywords: keywords,
            description: description,
            h1: h1,
            h2: h2,
            img: img,
            canonical: canonical,
            robots: robotsData,
            robotsmeta: robots,
            robotsurl: browser.robotsUrl(url),
            hreflangs: hreflangs,
            sitemaps: sitemaps
          });
        }, (err) => {
          event.sendMessage({
            type: event.SOURCE_EXTENSION,
            from: event.SOURCE_CONTENT,
            message: "pageinfo",
            keywords: keywords,
            description: description,
            h1: h1,
            h2: h2,
            img: img,
            canonical: canonical,
            robots: robots,
            robotsmeta: '',
            robotsurl: '',
            hreflangs: hreflangs,
            sitemaps: []
          });
        })
        break
    }
  }
  sendResponse({})
});


