import React from 'react';
import { createRoot } from 'react-dom/client';
import { EventStorage } from '../helpers/EventStorage'
import Toolbar from './toolbar'
// jQuery stuff reuired for highlighting
import mozbarquery from 'jquery'
import 'jquery-highlight'
import { LocalStorage } from '../helpers/LocalStorage'
import Serp from './serp'
import { MetaStorage } from '../helpers/MetaStorage'
import axios from 'axios'
declare var global: any;
global.jQuery = mozbarquery;

const mozbar_toolbar_id = 'moztoolbar-wrapper'
const mozbar_serp_id = 'mozbar-serp-id'

/**
 * Class to operate with browser content
 */
class BrowserApi {
  /**
   * Check if page should show no toolbar data
   * @param url
   */
  showToolbarData(url: string): boolean {
    // Check excluded domains
    const excludedDomains = [
      'search.google.com',
      'www.search.google.com',
    ]
    let url_proc = new URL(url)?.hostname
    if (excludedDomains.includes(url_proc))
      return false

    // Check google domains
    if (url.search('.google.') > 0) {
      if (this.checkSE(url)) {
        return true
      } else {
        return false
      }
    }
    return true
  }

  /**
   * Check if page is search engine page
   * @param url
   */
  checkSE(url: string): string | boolean {
    if (url.search('.google.[^\/]*/search')>0 || url === 'https://www.google.com/' || url === 'https://google.com/') {
      return 'google'
    }
    if (url.search('search.yahoo.[^\/]*/search')>0 || url === 'https://www.yahoo.com/' || url === 'https://yahoo.com/') {
      return 'yahoo'
    }
    if (url.search('.bing.[^\/]*/search')>0 || url === 'https://www.bing.com/' || url === 'https://bing.com/') {
      return 'bing'
    }
    return false
  }

  /**
   * Get SE keyword
   * @param url
   */
  getSEKeyword(engine: string, url: string): string {
    switch (engine) {
      case 'google':
        const urlParams = new URLSearchParams(url);
        return urlParams.get('q') ? urlParams.get('q') as string : "";
      case 'yahoo':
        break
      case 'bing':
        break
    }
    return ''
  }

  /**
   * Do updates for page styles to show toolbar on top properly
   * @param show
   */
  modifyPageStylesToolbar(show: boolean = true) {
    let elements
    const body = document.querySelector("body")
    if (show) {
      // Update HTML page to set all styles top:0 to top:48
      elements = document.querySelectorAll('[style]:not([style=""])')
      if (elements) {
        Array.prototype.forEach.call(elements, function (el) {
          if (el.style.top && el.getAttribute('mozobaroldel') === null) {
            const oldStyles = el.getAttribute('style')
            el.setAttribute('mozobaroldel', oldStyles ? oldStyles : '')
            el.style.top = (el.style.top + 48) + "px"
          }
        })
      }
      // Update styles for body
      if (body && body.getAttribute('mozobarold') === null) {
        const oldStyles = body.getAttribute('style')
        body.setAttribute('style', oldStyles ? oldStyles + '; ' : '' + 'margin-right:0px !important; margin-left:0px !important; margin-top: 48px !important; position: absolute !important; width: 100% !important;')
        body.setAttribute('mozobarold', oldStyles ? oldStyles : '')
      }
    } else {
      // Update HTML page to restore all modified styles
      elements = document.querySelectorAll('[mozobaroldel]')
      if (elements) {
        Array.prototype.forEach.call(elements, function (el) {
          const oldStyles = el.getAttribute('mozobaroldel')
          if (oldStyles!==null) el.setAttribute('style', oldStyles)
        })
      }
      if (body) {
        const oldStyles = body.getAttribute('mozobarold')
        if (oldStyles!==null) {
          body.setAttribute('style', oldStyles)
          body.removeAttribute('mozobarold')
        }
      }
    }
  }

  /**
   * Dock toolbar panel
   * @param type
   */
  dockTo(type: string) {
    let elements
    const doc = document.getElementById(mozbar_toolbar_id)
    if (doc) {
      switch (type) {
        case 'top':
          this.modifyPageStylesToolbar()
          doc.classList.remove('moztoolbar-dock-bottom')
          break
        case 'bottom':
          this.modifyPageStylesToolbar(false)
          doc.classList.add('moztoolbar-dock-bottom')
          break
        default:
          doc.classList.remove('moztoolbar-dock-bottom')
          break
      }
    }
  }

  /**
   * Show toolbar on content page
   * There are 2 conditions to show a toolbar
   *  - toolbar is enabled
   *  - it is not in the block list
   */
  showToolbar(){
    const exists = document.getElementById(mozbar_toolbar_id)
    if (!exists) {
      const ls = new LocalStorage()
      ls.get('config').then((res: any) => {
        const meta = new MetaStorage()
        const browser = new BrowserApi()
        const showData = browser.showToolbarData(document.location.href)
        if (!meta.matchBlockList(window.location.href, res?.block) && showData) {
          const body = document.querySelector('body')
          const app = document.createElement('div')
          app.id = mozbar_toolbar_id
          app.classList.add('active')
          if (body) {
            this.modifyPageStylesToolbar()
            body.prepend(app)
            const root = createRoot(app);
            root.render(<Toolbar configData={res}/>)
          }
        }
      })
    }
  }

  /**
   * Hide toolbar on content page
   */
  hideToolbar() {
    const toolbar = document.getElementById(mozbar_toolbar_id)
    if (toolbar) {
      this.modifyPageStylesToolbar(false)
      toolbar.remove()
    }
  }

  /**
   * Get Toolbar visibility
   */
  statusToolbar(){
    const toolbar = document.getElementById(mozbar_toolbar_id)
    if (toolbar) {
      return true
    } else {
      return false
    }
  }

  /**
   * Get SERP links from the page
   */
  getSERPLinks(ignoreSerpBar: boolean = false, includeSERP = true, includePlaces: boolean = false) {
    let list
    const links: string[] = []
    const titles: string[] = []
    const texts: string[] = []
    const elements: any[] = []
    let positionAppend = 0

    const se = this.checkSE(window.location.href)
    switch (se) {
      case 'google':
        positionAppend = -1
        if (includeSERP) {
          list = document.getElementById('rso')?.querySelectorAll('div[jscontroller][data-hveid]')
          if (list && list?.length && list?.length > 0) {
            // Get all links
            Array.prototype.forEach.call(list, function (el) {
              if (
                (
                  el.parentElement.getAttribute('id') == 'rso'
                  || el.parentElement.parentElement.getAttribute('id') == 'rso'
                  || el.parentElement.parentElement.parentElement.getAttribute('id') == 'rso'
                  || el.parentElement.parentElement.parentElement.parentElement.getAttribute('id') == 'rso'
                ) && (
                  !el.querySelector('.' + mozbar_serp_id) || ignoreSerpBar
                )
              ) {
                // Try to get page link
                const href = el.querySelector('a')
                if (href && href.getAttribute('href')) {
                  const url = href.getAttribute('href')
                  // Check link is valid url
                  if (url !== '#' && url.search('://') > 0) {
                    // Push link and element
                    links.push(url)
                    elements.push(el)
                    // Try to get page title
                    const title = el.querySelector('h3')
                    if (title && title.innerText) titles.push(title.innerText)
                    else titles.push('')
                    // Try to get page description
                    const description = el.querySelector('[data-sncf="1"]')?.innerText
                    if (description) texts.push(description)
                    else texts.push("")
                  }
                }
              }
            })
          }
        }
        // Include places
        if (includePlaces) {
          // Places
          list = document.getElementById('rso')?.querySelectorAll('div[data-thtn]')
          if (list && list?.length && list?.length > 0) {
            // Get all links
            Array.prototype.forEach.call(list, function (el) {
              const href = el.querySelector('a')
              if (href && href.getAttribute('href')) {
                const url = href.getAttribute('href')
                // Check link is valid url
                if (url !== '#' && url.search('://') > 0) {
                  // Push link and element
                  links.push(url)
                  elements.push(el.children[0])
                  // Try to get page title
                  const title = el.querySelector('div[role="heading"]')
                  if (title && title.innerText) titles.push(title.innerText)
                  else titles.push('')
                  // No description
                  texts.push("")
                }
              }
            })
          }
          // Local places
          list = document.getElementsByClassName('rllt__details')
          if (list && list?.length && list?.length > 0) {
            Array.prototype.forEach.call(list, function (el) {
              const heading = el.querySelector('[role="heading"]')
              if (heading) {
                const title = heading.querySelector('span').innerText
                // Check link is valid url
                if (title) {
                  // Push link and element
                  const parent = el.closest('div[jscontroller]').parentElement
                  if (parent) {
                    const href = parent.querySelector('a[href]')
                    if (href && href.getAttribute('href')) {
                      const url = href.getAttribute('href')
                      if (url !== '#' && url.search('://') > 0) {
                        links.push(url)
                        // querySelector('a div')
                        elements.push(href.parentElement.children[0].children[0])
                        // Try to get page title
                        titles.push(title)
                        // No description
                        texts.push("")
                      }
                    }
                  }
                }
              }
            })
          }
        }
        break

      case 'yahoo':
        positionAppend = 0
        if (includeSERP) {
          list = document.getElementById('web')?.children[1]?.children
          if (list && list?.length && list?.length > 0) {
            // Get all links
            Array.prototype.forEach.call(list, function (el) {
              if (el.children && el.children.length == 1 && el.children[0].children.length == 2 && (!el.querySelector('.' + mozbar_serp_id) || ignoreSerpBar)) {
                // Try to get page link
                const href = el.querySelector('a')
                if (href && href.getAttribute('href')) {
                  const url = href.getAttribute('href')
                  // Check link is valid url
                  if (url !== '#' && url.search('://') > 0) {
                    // Push link and element
                    links.push(url)
                    elements.push(el)
                    // Try to get page title
                    const title = el.querySelector('h3')
                    if (title && title.innerText) titles.push(title.innerText)
                    else titles.push('')
                    // Try to get page description
                    const description = el.children[0].children[1]?.innerText
                    if (description) texts.push(description)
                    else texts.push("")
                  }
                }
              }
            })
          }
        }
        break

      case 'bing':
        positionAppend = -1
        if (includeSERP) {
          list = document.getElementById('b_results')?.children
          if (list && list?.length && list?.length > 0) {
            // Get all links
            Array.prototype.forEach.call(list, function (el) {
              if (el.children && el.children.length >= 2 && (!el.querySelector('.' + mozbar_serp_id) || ignoreSerpBar)) {
                // Try to get page link
                const href = el.querySelector('a')
                if (href && href.getAttribute('href')) {
                  const url = href.getAttribute('href')
                  // Check link is valid url
                  if (url !== '#' && url.search('://') > 0) {
                    // Push link and element
                    const curl = url.split('#')[0]
                    links.push(curl)
                    elements.push(el)
                    // Try to get page title
                    const title = el.querySelector('h2')
                    if (title && title.innerText) titles.push(title.innerText)
                    else titles.push('')
                    // Try to get page description
                    const description = el.querySelector('[role="contentinfo"]')?.innerText
                    if (description) texts.push(description)
                    else texts.push("")
                  }
                }
              }
            })
          }
        }
        break
    }

    return {links: links, elements: elements, titles: titles, texts: texts, positionAppend: positionAppend}
  }

  /**
   * Display all SERP bars based on data and links provided
   * @param request
   */
  displaySERPbars(request: any) {
    // TODO: Tricky part since probably HTML page could be changed from last showSERP call
    // May be needs refactoring
    const ls = new LocalStorage()

    ls.get('config').then((res: any) => {
      const { elements, links, positionAppend} =
        this.getSERPLinks(
          true,
          res.serp ? res.serp : false,
          res.places ? res.places : false
        )
      const toolbardata = request.data.data

      for (let i = 0; i < elements.length; i++) {
        const elem = elements[i]
        const url = links[i]

        // If element exists then remove it to create a new after
        if (elem.querySelector('.' + mozbar_serp_id))
          elem.querySelector('.' + mozbar_serp_id).remove()

        // Find proper data in toolbardata
        const data = toolbardata[i]?.page_overview

        // Build data
        let info
        if (data) {
          info = {
            page_authority: data.page?.page_authority,
            domain_authority: data.domain?.domain_authority,
            brand_authority: data.domain_extended?.brand_authority,
            da: {
              ld: data.domain_extended?.linking_domains_count,
              lp: data.domain_extended?.linking_pages_count,
              rk: data.domain_extended?.ranking_keywords_count,
            },
            pa: {
              ld: data.page_extended?.linking_domains_count,
              lp: data.page?.linking_pages_count,
              rk: data.page_extended?.ranking_keywords_count,
            },
            links: [url],
            created: new Date().getTime()
          }
        }

        // Add react component
        const app = document.createElement('div')
        app.classList.add(mozbar_serp_id)
        if (positionAppend === -1) {
          elem.appendChild(app)
        } else {
          elem.children[positionAppend].append(app)
        }
        const root = createRoot(app);
        root.render(<Serp url={url} configData={res} toolbarData={info}/>)
      }
    })
  }

  /**
   * Display all SERP bars based on data and links provided
   * @param request
   */
  exportSERPdata(request: any, includeSERP: boolean = true, includePlaces: boolean = false) {
    // TODO: Tricky part since probably HTML page could be changed from last showSERP call
    const { titles} = this.getSERPLinks(true, includeSERP, includePlaces)
    const meta = new MetaStorage()
    const items = []
    const elements = request.data.data
    for(let i = 0; i< elements.length; i++) {
      const item = elements[i]
      const page = item?.page_overview
      items.push({
        position: i+1,
        url: item.target_query.original_target_query.query,
        title: titles[i],
        da: page.domain.domain_authority,
        da_links: page.domain_extended.linking_pages_count + page.domain_extended.linking_domains_count,
        da_domains: page.domain_extended.linking_domains_count,
        pa: page.page.page_authority,
        pa_links: page.page.linking_pages_count + page.page_extended.linking_domains_count,
        pa_domains: page.page_extended.linking_domains_count,
        ba: page.domain_extended.brand_authority,
      })
    }
    const engine = this.checkSE(window.location.href)
    if (engine) {
      const filename =
        this.getSEKeyword(engine as string, window.location.search) + '-' +
        engine + '-' + (new Date().toDateString())
      meta.exportCSV(items, 'Position, URL, Page Title, ' +
        'Domain Authority, Domain - Inbound Links, Domain - Linking Domains, ' +
        'Page Authority, Page - Inbound Links, Page - Linking Domains, Brand Authority',
        filename)
    }  }

  /**
   * Show SERP block
   */
  showSERP() {
    const body = document.querySelector("body")
    const app = document.createElement('div')
    app.id = mozbar_serp_id
    if (body) {
      const ls = new LocalStorage()
      ls.get('config').then((res: any) => {
        const { links } = this.getSERPLinks(
          true,
          res.serp ? res.serp : false,
          res.places ? res.places : false
        )
        if (links.length == 0) return
        const event = new EventStorage()
        event.sendMessage(event.buildMessage(event.SOURCE_BACKGROUND, event.SOURCE_CONTENT, 'serp', { links: links }))
      })
    }
  }

  /**
   * Hide SERP block
   */
  hideSERP(includePlaces = false){
    document.querySelectorAll('.' + mozbar_serp_id).forEach(elem => elem.remove());
    const serp = document.getElementById(mozbar_serp_id)
    if (serp) {
      serp.remove()
    }
  }

  /**
   * Get SERP status
   */
  statusSERP(){
    const serp = document.getElementById(mozbar_serp_id)
    if (serp) {
      return true
    } else {
      return false
    }
  }

  /**
   * Do filter on the page content
   */
  tag(selector: string, attribute: string[]): any[] {
    const items: any[] = []
    const filter = (item: Element) => {
      return !item.closest('#moztoolbar-wrapper')
        && !item.closest('.mozbar-serp-overlay')
    }
    if (!attribute || attribute.length === 0) {
      document.querySelectorAll(selector).forEach( (item) => {
        if (filter(item) && items.indexOf(item.innerHTML) === -1) {
          items.push(item.innerHTML)
        }
      })
    } else {
      document.querySelectorAll(selector).forEach( (item) => {
        if (filter(item)) {
          let data: any
          if (attribute.length === 1) {
            data = item.getAttribute(attribute[0])
            if (data) {
              if (items.indexOf(data) === -1) {
              items.push(data)
                }
            }
          } else {
            data = {}
            attribute.forEach((attr) => {
              const itm: string | null = item.getAttribute(attr)
              if (itm) {
                data[attr] = itm
              }
            })
            // In case all attribute has values save the data
            if (Object.keys(data).length === attribute.length) {
              items.push(data)
            }
          }
        }
      })
    }
    return items
  }

  /**
   * Show or hide highlighting on current page for links and keywords provided
   *     --link-followed: #B3E5A0;
   *     --link-nofollow: #FF7F75;
   *     --link-external: #88F0FF;
   *     --link-internal: #FFD05F;
   *     --link-highlight: #54E8CC;
   */
  highlight(type: string, data: any){
    const show: boolean = data.value
    const keyword: string = data.keyword

    /**
     * Build styles to mark A tag based on class names
     */
    const buildStyle = (link: HTMLAnchorElement) => {
      let isSet = false
      let isDouble = false
      let style = ''
      let backgroundColor = ''
      let borderColor = ''

      const followed = link.getAttribute('mozbar_background_followed')
      const nofollow = link.getAttribute('mozbar_background_nofollow')
      const internal = link.getAttribute('mozbar_background_internal')
      const external = link.getAttribute('mozbar_background_external')

      if (followed && external) {
        isSet = isDouble = true
        style = "background-color: #88F0FF; border-left-color: #B3E5A0; border-left-width: 3px; border-left-style: solid"
        borderColor = "#B3E5A0"
        backgroundColor = "#88F0FF"
      } else if (followed && internal) {
        isSet = isDouble = true
        style = "background-color: #FFD05F; border-left-color: #B3E5A0; border-left-width: 3px; border-left-style: solid"
        borderColor = "#B3E5A0"
        backgroundColor = "#FFD05F"
      } else if (nofollow && external) {
        isSet = isDouble = true
        style = "background-color: #88F0FF; border-left-color: #FF7F75; border-left-width: 3px; border-left-style: solid"
        borderColor = "#FF7F75"
        backgroundColor = "#88F0FF"
      } else if (nofollow && internal) {
        isSet = isDouble = true
        style = "background-color: #FFD05F; border-left-color: #FF7F75; border-left-width: 3px; border-left-style: solid"
        borderColor = "#FF7F75"
        backgroundColor = "#FFD05F"
      } else if (followed) {
        isSet = true
        style = "background-color: #B3E5A0"
        backgroundColor = "#B3E5A0"
      } else if (nofollow) {
        isSet = true
        style = "background-color: #FF7F75"
        backgroundColor = "#FF7F75"
      } else if (external) {
        isSet = true
        style = "background-color: #88F0FF"
        backgroundColor = "#88F0FF"
      } else if (internal) {
        isSet = true
        style = "background-color: #FFD05F"
        backgroundColor = "#FFD05F"
      }

      if (isSet) {
        if (link.getAttribute('style')) {
          link.style.backgroundColor = backgroundColor
          if (isDouble) {
            link.style.borderLeftColor = borderColor
            link.style.borderLeftWidth = "3px"
            link.style.borderLeftStyle = "solid"
          }
        } else {
          link.setAttribute('style', style)
        }
      } else {
        if (link.getAttribute('style')) {
          link.style.backgroundColor = ''
          link.style.borderLeftWidth = '0px'
        }
      }
    }

    /**
     * Check link type based on HTML and set proper class name to element
     * @param link
     * @param type
     */
    const checkLinkType = (link: HTMLAnchorElement, type: string) => {
      const origin= window.location.origin
      const href = link.getAttribute('href')
      switch(type) {
        case 'followed':
          const val1 = link.getAttribute('rel')?.search('nofollow')
          if (val1 === undefined || val1 === -1)
            return true
          break
        case 'nofollow':
          const val2 = link.getAttribute('rel')?.search('nofollow')
          if (val2 !== undefined && val2 != -1)
            return true
          break
        case 'external':
          if (href && href.search(origin) === -1 && (href.search('https://') >= 0 || href.search('http://') >= 0)) {
            return true
          }
          break
        case 'internal':
          if (!href || href?.search(origin) >= 0 || href?.search('https://') === -1 || href?.search('http://') === -1 ) {
            return true
          }
          break
      }
      return false
    }

    if (type === 'keywordhighlight') {
      // This part is using jQuery highlight function
      // @ts-ignore
      mozbarquery('body').unhighlight({
        element: 'span',
        className: 'mozbar_background_keyword'
      })
      if (show) {
        // @ts-ignore
        mozbarquery('body').highlight(keyword, {
          element: 'span',
          className: 'mozbar_background_keyword'
        })
      }
    } else {
      // find all a tags
      const allATags = document.getElementsByTagName("a")
      for (let i = 0; i < allATags.length; i++) {
        if (show) {
          if (checkLinkType(allATags[i], type)) {
            allATags[i].setAttribute('mozbar_background_' + type, "true")
          } else {
            allATags[i].removeAttribute('mozbar_background_' + type)
          }
        } else {
          allATags[i].removeAttribute('mozbar_background_' + type)
        }
        buildStyle(allATags[i])
      }
    }
  }

  /**
   * Calculate count of words in the document
   * @param keyword
   */
  countwords(keyword: string) {
    const regexp = new RegExp(keyword, 'gi')
    let text = document.body.innerText;
    return (text.match(regexp) || []).length;
  }

  /**
   * Get robots url
   * @param url
   */
  robotsUrl(url: string) {
    if (url.charAt(url.length-1)=='/')
      url += 'robots.txt'
    else
      url += '/robots.txt'
    return url
  }

  /**
   * Get robots file content
   * @param url
   */
  async robots(url: string) {
    return await axios.get(this.robotsUrl(url))
  }

  /**
   * Create extesion icon
   * @param da
   * @param width
   * @param height
   */
  createDAIcon (da: number, width: number, height: number) {
    const BAR_HEIGHT_PCT = 20
    const BAR_BORDER_PCT = 5

    const border = Math.round(height * (BAR_BORDER_PCT / 100))
    const barHeight = (BAR_HEIGHT_PCT/100) * height
    const barX = border
    const barY = height - barHeight - border
    const barWidth = width - (border * 2)

    try {
      const canvas = document.createElement('canvas')
      canvas.width = width
      canvas.height = height

      const context = canvas.getContext('2d')
      if (context) {
        context.fillStyle = '#4e5c5f'
        context.fillRect(0, 0, width, height)
        context.fillStyle = '#e6e8e8'
        context.fillRect(barX, barY, barWidth, barHeight)
        context.fillStyle = '#4dbdeb'
        context.fillRect(barX, barY, barWidth * (da / 100), barHeight)

        const fontSize = width == 19 ? 10 : 20
        context.font = "bold #{fontSize}px Open Sans, sans-serif"
        context.fillStyle = '#e6e8e8'
        context.textAlign = 'center'
        context.textBaseline = 'middle'
        context.fillText(da.toString(), width / 2, (height - barHeight) / 2)
      }
      return canvas
    }
    catch(ex) {
      console.log(ex)
    }
  }
}

export {BrowserApi}