import React, { FC, useEffect, useState } from 'react'
import {
  Close, DoNotDisturb,
  GetApp, Lock,
  VerticalAlignBottom, VerticalAlignTop
} from '@mui/icons-material'
import {
  Chip,
  Divider,
  FormControl, FormControlLabel, FormGroup,
  ListItemIcon, ListItemText,
  MenuItem,
  Select,
  Stack,
  styled,
  Switch,
  Typography
} from '@mui/material'
import { PieChart, useDrawingArea } from '@mui/x-charts'
import './toolbar.css'
import { BrowserApi } from './api'
import { EventStorage } from '../helpers/EventStorage'
import { LocalStorage } from '../helpers/LocalStorage'
import { runtime } from 'webextension-polyfill'
import { MetaStorage } from '../helpers/MetaStorage'
import Tooltip, { tooltipClasses, TooltipProps } from '@mui/material/Tooltip'

interface ToolbarProps {
  configData: any,
  toolbarData?: any
}

/**
 * Available extension commands
 */
enum Command {
  None = 'none',
  Analyze= 'analyze',
  Keywords= 'keywords',
  Optimization = 'optimization',
  Export = 'export'
}

/**
 * Command visibility level
 */
enum VisibilityLevel {
  None = 'none',
  Community = 'community',
  Pro = 'pro'
}

/**
 * Get current url
 */
const currentUrl = (hostOnly: boolean = true) => {
  if (hostOnly)
    return window.location.protocol + '//' +  window.location.hostname + window.location.pathname
  else
    return window.location.href
}

const Toolbar: FC<ToolbarProps> = (props: ToolbarProps) => {
  const [dockIcon, updateDockIcon] = useState(<VerticalAlignBottom className={'moztoolbar-icon'}/>)
  const [dockMessage, updateDockMessage] = useState("Dock to bottom")
  const [dockToTop, updateDockToTop] = useState(props.configData.dock === 'bottom' ? false : true)
  const [toolbarData, updateToolbarData] = useState<any>(props.toolbarData)
  const [configData, updateConfigData] = useState<any>(props.configData)
  const [commandSelected, updateCommandSelected] = useState<Command>(Command.None)
  const [profileSelected, updateProfileSelected] = useState(-1)
  const [darkMode, updateDarkMode] = useState(props.configData.theme)
  const [quota, setQuota] = useState("")

  /**
   * Dock handling
   */
  const dock = (dockToTop: boolean) => {
    const browser = new BrowserApi()
    if (dockToTop) {
      browser.dockTo('top')
      updateDockIcon(<VerticalAlignBottom className={['moztoolbar-icon', 'moztoolbar-cursor'].join(' ')}/>)
      updateDockMessage('Dock to bottom')
    }
    else {
      browser.dockTo('bottom')
      updateDockIcon(<VerticalAlignTop className={['moztoolbar-icon', 'moztoolbar-cursor'].join(' ')}/>)
      updateDockMessage("Dock to top")
    }
  }

  /**
   * Init toolbar: request data
   */
  useEffect(() => {
    const event = new EventStorage()
    if (!toolbarData) {
      event.sendMessage(event.buildMessage(event.SOURCE_BACKGROUND, event.SOURCE_CONTENT, 'status-request', {}))
    }
    // TODO: move it to main event handler
    chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
      if (request.type === event.SOURCE_CONTENT) {
        switch (request.message) {
          case 'status':
            console.log('Toolbar data: ', request.data)
            if (!toolbarData || request.data.created > toolbarData.created) {
              updateToolbarData(request.data)
            }
            break
        }
      }
    })
    // Verify profile selected based on the website
    if (configData?.profileSelected) {
      updateProfileSelected(configData?.profileSelected)
    }
    dock(dockToTop)
  }, [])


  /**
   * Main event cycle
   */
  const ls = new LocalStorage()
  ls.storage().onChanged.addListener((changes, namespace) => {
    for (let [key, { oldValue, newValue }] of Object.entries(changes)) {
      switch(key) {
        case 'config':
          updateConfigData(newValue)
          updateDarkMode(newValue?.theme)
          if (newValue?.dock) {
            const dockState = newValue?.dock === 'top' ? true : false
            updateDockToTop(dockState)
            dock(dockState)
          }
          // Update quota message
          if (newValue?.quota_current && newValue?.quota_max && newValue?.period_reset) {
            const [message, ] = meta.buildQuotaMessage(newValue.quota_current, newValue.quota_max, newValue.period_reset, newValue.is_pro, true)
            setQuota(message)
          }

          if (newValue?.toolbar) {
            // updateToolbarData(newValue?.toolbar)
          }
          break
      }
    }
  })

  /**
   * Get toolbar visibility level
   */
  const visibility = (): VisibilityLevel => {
    if (!configData || !configData.token) {
      return VisibilityLevel.None
    }
    if (!configData.is_pro) {
      return VisibilityLevel.Community
    }
    return VisibilityLevel.Pro
  }

  /**
   * Blur specified text
   * @param text
   */
  const blurText = (text: string) => {
    return (
      <div style={{ filter: 'blur(8px)', pointerEvents: 'none', color: 'var(--text-main)' }}>
        lorem
      </div>
    )
  }

  /**
   * Update extension property in the local storage
   * @param property
   * @param value
   */
  const updateBackendProperty = (property: string, value: any) => {
    const ls = new LocalStorage()
    ls.push('config', {[property]: value})
  }

  /**
   * Choose command
   * @param type
   */
  const commandClick = (type: Command) => {
    const browser = new BrowserApi()
    switch(type) {
      case Command.Export:
        if (visibility() !== VisibilityLevel.None) {
          const ls= new LocalStorage()
          ls.get('config').then((res: any) => {
            const {links} = browser.getSERPLinks(
              true,
              res.serp ? res.serp : false,
              res.places ? res.places : false
            )
            const event = new EventStorage()
            event.sendMessage(event.buildMessage(event.SOURCE_BACKGROUND, event.SOURCE_CONTENT, 'serp-export', { links: links }))
          })
        }
        break
    }
    updateCommandSelected(type)
  }

  /**
   * Tooltip component
   */
  const BootstrapTooltip = styled(({ className, ...props }: TooltipProps) => (
    <Tooltip {...props} arrow classes={{ popper: className }} />
  ))(({ theme }) => ({
    [`& .${tooltipClasses.arrow}`]: {
      color: "#616161E5",
    },
    [`& .${tooltipClasses.tooltip}`]: {
      backgroundColor: "#616161E5",
      color: "#ffffff",
      fontSize: "12px"
    },
  }))

  /**
   * Build pie diagram
   * @param size
   * @param value
   */
  const buildPie = (size: number, value: number | null, url?: string, isBa: boolean = false) => {
    const sizeInner = size - 9
    const angle = value ?? 0

    // Depending on theme switch pie color
    let color
    if (isBa) {
      color = '#FF9F2C'
      if (darkMode) color = '#FFD262'
    } else {
      color = '#0077BB'
      if (darkMode) color = '#4DBEEB'
    }

    const StyledText = styled('text')(({ theme }) => ({
      fill: 'var(--text-main) !important',
      textAnchor: 'middle',
      dominantBaseline: 'central',
      fontSize: 14,
      color: 'var(--text-main) !important'
    }))

    function PieCenterLabel({ children }: { children: React.ReactNode }) {
      const { height, top } = useDrawingArea()
      return (
        <StyledText x={size + 5} y={top + height / 2} className={"moztoolbar-highlight"} style={children as number>=100 ? {fontSize: "12px"} : {}}>
          {children}
        </StyledText>
      )
    }

    return (
      <span className={"moztoolbar-cursor moztoolbar-highlight"} onClick={(ev) => meta.openContentLink(url ? url : '')}>
        <PieChart
          series={[
            {
              data: [
                { value: angle, color: color },
                { value: 100 - angle, color: darkMode ? '#092A46' : '#BBB' },
              ],
              innerRadius: sizeInner,
              outerRadius: size,
              paddingAngle: 0,
              cx: size,
              cy: size,
            }
          ]}
          width={size*2 + 10}
          height={size*2 + 10}
          slotProps={{
            legend: { hidden: true },
          }}
          tooltip={{trigger: 'none'}}
        >
          <PieCenterLabel>{angle ? angle : '-'}</PieCenterLabel>
        </PieChart>
      </span>
    )
  }

  /**
   * Add to blocklist
   */
  const blockToolbar = () => {
    const browser = new BrowserApi()
    browser.hideToolbar()
    const ls = new LocalStorage()
    ls.get('config').then((res: any) => {
      // Make sure we push domain or subdomain to block list
      const url = (new MetaStorage()).getDomain(currentUrl(false), true, true)
      if (res.block) res.block += '\n' + url
      else res.block = url
      ls.push('config', {'block': res.block})
    })
  }

  /**
   * Close toolbar
   */
  const closeToolbar = () => {
    const browser = new BrowserApi()
    updateBackendProperty('toolbar', false)
    browser.hideToolbar()
  }

  /**
   * Get logo
   */
  const logoUrl = () => {
    return (
      <div className={"moztoolbar-logo"} style={{verticalAlign: "center"}}>
        <svg aria-labelledby="moz-logo-title-header" role="img" width="85" height="25">
          <title>Moz logo</title>
          <path d="M71 16L82.99 3h-25.1c-.48.018-.866.4-.89.882v2.736C54.697 2.696 49.97 0 44.5 0 38.036 0 32.61 3.76 31 8.863V3h-4.38c-1.043.015-1.957.478-2.62 1.177l-8.498 9.325L7 4.177C6.34 3.477 5.427 3.015 4.383 3H0v19h5.117c.492-.024.863-.42.883-.91V12l9.5 10.5L25 12v9.09c.017.49.415.886.905.91H31v-6.863C32.61 20.24 38.036 24 44.5 24c7.732 0 14-5.373 14-12 0-1.038-.17-2.04-.46-3H69L57 22h25.104c.48-.018.872-.403.896-.884V16H71zm-26.452 1.96c-3.764 0-6.818-2.668-6.818-5.96 0-3.293 3.053-5.96 6.818-5.96 3.768 0 6.822 2.668 6.822 5.96s-3.053 5.96-6.822 5.96z"></path>
        </svg>
      </div>
    )
  }

  /**
   * Update user SE profile
   * @param profile
   */
  const updateProfile = (index: number) => {
    updateProfileSelected(index)
    // Reload the page based on selected profile
    if (configData?.profiles[index-1]) {
      const engine = configData?.profiles[index-1].engine
      const country = configData?.profiles[index-1].country
      let countries:any[] = []
      switch (engine) {
        case 'google':
          countries = meta.google_countries()
          break
        case 'yahoo':
          countries = meta.yahoo_countries()
          break
        case 'bing':
          countries = meta.bing_countries()
          break
      }
      if (countries) {
        const data = countries.filter((item) => item.code === country)
        if (data) {
          const ls = new LocalStorage()
          ls.push('config', {'profileSelected': index})
          const buildUrl = data[0].url + window.location.pathname + window.location.search + window.location.hash
          window.location.href = buildUrl
        }
      }
    }
  }

  /**
   * Change dark mode from extension
   * @param isDark
   */
  const changeDarkMode = (isDark: boolean) => {
    updateBackendProperty('theme', isDark)
    updateDarkMode(isDark)
  }


  /**
   * Build toolbar right buttons
   */
  const meta = new MetaStorage()
  const toolbarRightButtons = () => {
    return (
      <Stack alignItems="center" direction="row" spacing={2} justifySelf={'flex-end'}>
        {visibility() === VisibilityLevel.None && (
          <div
            onClick={ev => meta.openContentLink(meta.metrics_link_new_account)}>
            <Stack alignItems="center" direction="row" spacing={1}>
              <div className={['moztoolbar-cursor', 'moztoolbar-text'].join(' ')}>
                <Typography className={'moztoolbar-text'} sx={{ display: { xs: 'none', sm: 'none', md: 'none', lg: 'none', xl: 'block' } }}>
                  Get Link Metrics with a<br/>FREE Moz Community Account
                </Typography>
              </div>
              <Chip className={'moztoolbar-cursor'} label="Sign Up"
                    icon={<Lock style={{ fontSize: '20px', color: '#000000', paddingLeft: '4px' }}/>}
                    sx={{ borderRadius: '15px', color: '#000000', fontSize: '13px', background: '#FFD05F' }}/>
            </Stack>
          </div>
        )}
        {visibility() === VisibilityLevel.Community && (
          <div
            onClick={ev => meta.openContentLink(meta.metrics_link_upgrade)}>
            <Stack alignItems="center" direction="row" spacing={1}>
              <div className={['moztoolbar-cursor', 'moztoolbar-text'].join(' ')}>
                <Typography className={'moztoolbar-text'} sx={{ display: { xs: 'none', sm: 'none', md: 'none', lg: 'none', xl: 'block' }, whiteSpace: 'pre-wrap' }}>
                  {quota}
                </Typography>
              </div>
              <Chip className={'moztoolbar-cursor'} label="Premium"
                    icon={<Lock style={{ fontSize: '20px', color: '#000000', paddingLeft: '4px' }}/>}
                    sx={{ borderRadius: '15px', color: '#000000', fontSize: '13px', background: '#FFD05F' }}/>
            </Stack>
          </div>
        )}
        {visibility() === VisibilityLevel.Pro && (
          <div
            onClick={ev => meta.openContentLink(meta.metrics_link_upgrade)}>
            <Stack alignItems="center" direction="row" spacing={1}>
              <div className={['moztoolbar-cursor', 'moztoolbar-text'].join(' ')}>
                <Typography className={'moztoolbar-text'} sx={{ display: { xs: 'none', sm: 'none', md: 'none', lg: 'none', xl: 'block' }, whiteSpace: 'pre-wrap' }}>
                  {quota}
                </Typography>
              </div>
            </Stack>
          </div>
        )}
        <div>
          <Stack alignItems="center" direction="row" spacing={1}>
            <FormGroup>
              <FormControlLabel control={<Switch
                type={'checkbox'}
                checked={darkMode}
                onChange={(ev) => changeDarkMode(ev.target.checked)}
                className={''}
              />} label="Dark mode" />
            </FormGroup>
          </Stack>
        </div>
        <div className={'moztoolbar-cursor'} style={{marginLeft: "0px"}}>
          <Chip label={dockMessage} variant={"outlined"} onClick={(ev) => {
            const dockState = !dockToTop
            dock(dockState)
            updateBackendProperty('dock', dockState ? 'top' : 'bottom')
            updateDockToTop(dockState)
          }} icon={dockIcon} />
        </div>
        <div style={{ marginRight: '4px' }} className={'moztoolbar-cursor'}>
          <Chip label={""} variant={"outlined"} onClick={blockToolbar} className={"nolabel"} icon={
            <BootstrapTooltip title={'Hide MozBar on this domain'} placement={'bottom'}>
              <DoNotDisturb className={'moztoolbar-icon'}/>
            </BootstrapTooltip>
          } />
        </div>
        <div style={{ marginRight: '20px', marginLeft: "10px" }} className={'moztoolbar-cursor'}>
          <Chip label={""} variant={"outlined"} onClick={closeToolbar} className={"nolabel"} icon={
            <BootstrapTooltip title={'Close toolbar'} placement={'bottom'}>
              <Close className={'moztoolbar-icon'}/>
            </BootstrapTooltip>
          } />
        </div>
      </Stack>
    )
  }

  /**
   * Main template
   */
  const browser = new BrowserApi()
  const engine = browser.checkSE(currentUrl())
  const showData = browser.showToolbarData(currentUrl())
  if (engine) {
    // Show only SE toolbar
    const profiles = []

    const se = (index: number, country: string, image: string, name: string) => {
      return (
        <MenuItem value={index}>
          <Stack direction={"row"} spacing={0} justifySelf={"center"} justifyContent={'center'} justifyItems={"center"} alignItems={"center"} sx={{height: "20px !important"}}>
            <ListItemIcon style={{textAlign: "center", display: "block", minWidth: "22px"}}>
              <img src={image} height={"16px"}/>
            </ListItemIcon>
            <ListItemText primary={name + ' ' + country} sx={{marginTop: "8px", marginLeft: "10px"}} />
          </Stack>
        </MenuItem>
      )
    }

    profiles.push(<MenuItem value={-1}>Not selected</MenuItem>)
    if (configData?.profiles && configData?.profiles?.length>0 ) {
      let index = 1
      configData?.profiles?.forEach((item: any) => {
        if (engine === item.engine) {
          profiles.push(
            se(index, item.country, meta.getSEImage(item.engine), item.name)
          )
        }
        index++
      })
    }

    return (
      <div id={"moztoolbar-anchor"} className={darkMode ? 'theme-dark' : 'theme-light'}>
        <Stack spacing={3} direction="row" justifyItems={"flex-start"} className={"moztoolbar-toolbar"}>
          <Stack alignItems="center" direction="row" spacing={2} justifyContent={'flex-start'}>
            <div>{logoUrl()}</div>
            <div></div>
            {visibility() === VisibilityLevel.Pro && (<>
              <div>
                <Stack alignItems="center" direction="row" spacing={1} justifyContent={'flex-start'}>
                  <GetApp
                    className={['moztoolbar-icon', 'moztoolbar-cursor'].join(' ')}
                    onClick={(ev) => commandClick(Command.Export)}
                  />
                  <Typography className={['moztoolbar-p', 'moztoolbar-cursor'].join(' ')}
                              onClick={(ev) => commandClick(Command.Export)}>
                    Export SERP
                  </Typography>
                </Stack>
              </div>
              <Divider variant={"middle"} orientation={"vertical"}/>
            </>)}
            <div>
              <Stack alignItems="center" direction="row" spacing={1} justifyContent={'flex-start'}>
                <Typography className={'moztoolbar-p'}>Search Profiles</Typography>
                <FormControl sx={{ m: 0, minWidth: 180 }} size={'small'}>
                  <Select
                    size={"small"}
                    value={profileSelected}
                    displayEmpty={true}
                    inputProps={{ 'aria-label': 'Without label' }}
                    onChange={(ev: any) => updateProfile(ev.target.value)}
                  >
                    {profiles}
                  </Select>
                </FormControl>
              </Stack>
            </div>
          </Stack>

          {toolbarRightButtons()}
        </Stack>
      </div>
    )
  } else if(!showData) {
    // Display no toolbar in case this is some Google not SERP page
    return (<></>)
  } else {
    // Show regular toolbar
    return (
      <div id={"moztoolbar-anchor"} className={darkMode ? 'theme-dark' : 'theme-light'}>
        <Stack spacing={2} direction="row" justifyItems={"flex-start"} className={"moztoolbar-toolbar"}>
          <Stack alignItems="center" direction="row" spacing={1} justifyContent={'flex-start'} justifyItems={"center"}>
            {logoUrl()}

            <div style={{marginLeft: "30px"}}>
              <BootstrapTooltip title={meta.domainAuthorityTooltip} placement={"top"} arrow>
                <Stack alignItems="center" direction="row" spacing={1}>
                  <h1 className="moztoolbar-h1">DA</h1>
                  {visibility() !== VisibilityLevel.None ? buildPie(20, toolbarData?.domain_authority, meta.buildMetricsLink(currentUrl(), 'domain')) : <></>}
                </Stack>
              </BootstrapTooltip>
            </div>

            <Divider variant={"middle"} orientation={"vertical"}/>
            <div>
              <BootstrapTooltip title={meta.linkingDomainsTooltip} placement={"bottom"}>
                <h2 className="moztoolbar-h2 moztoolbar-highlight">
                  {visibility() === VisibilityLevel.Pro ?
                    (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'domain'))}>{meta.numberFormat(toolbarData?.da?.ld, true)}</span>)
                    : blurText('')}
                </h2>
              </BootstrapTooltip>
              <Typography className="moztoolbar-p moztoolbar-cursor" onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'domain'))}>Domains</Typography>
            </div>
            <Divider variant={"middle"} orientation={"vertical"}/>
            <div className={"MuiDividerDiv"}>
              <BootstrapTooltip title={meta.inboundLinksTooltip} placement={"bottom"}>
                <h2 className="moztoolbar-h2 moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                  (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'domain'))}>{meta.numberFormat(toolbarData?.da?.tl, true)}</span>)
                  : blurText('')}</h2>
              </BootstrapTooltip>
              <Typography className="moztoolbar-p moztoolbar-cursor" onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'domain'))}>Links</Typography>
            </div>
            <Divider variant={"middle"} orientation={"vertical"}/>
            <div className={"MuiDividerDiv"}>
              <BootstrapTooltip title={meta.keywordsTooltip} placement={"bottom"}>
                <h2 className="moztoolbar-h2 moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                  (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'domain'))}>{meta.numberFormat(toolbarData?.da?.rk, true)}</span>)
                  : blurText('')}</h2>
              </BootstrapTooltip>
              <Typography className="moztoolbar-p moztoolbar-cursor" onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'domain'))}>Keywords</Typography>
            </div>
            <Divider variant={"middle"} orientation={"vertical"}/>
            <div className={"MuiDividerDiv"}>
              <BootstrapTooltip title={meta.spamScoreTooltip} placement={"bottom"} className={"moztoolbar-tooltip"}>
                <h2 className="moztoolbar-h2 moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                  (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'page'))}>{toolbarData?.pa?.sc>0 ? toolbarData?.pa?.sc + '%' : '-'}</span>)
                  : blurText('')}</h2>
              </BootstrapTooltip>
              <Typography className="moztoolbar-p moztoolbar-cursor" onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'page'))}>Spam</Typography>
            </div>

            <div style={{marginLeft: "30px"}}>
              <BootstrapTooltip title={meta.pageAuhorityTooltip} placement={"top"} arrow>
                <Stack alignItems="center" direction="row" spacing={1}>
                  <h1 className="moztoolbar-h1">PA</h1>
                  {visibility() !== VisibilityLevel.None ? buildPie(20, toolbarData?.page_authority, meta.buildMetricsLink(currentUrl(), 'page')) : <></>}
                </Stack>
              </BootstrapTooltip>
            </div>
            <Divider variant={"middle"} orientation={"vertical"}/>
            <div className={"MuiDividerDiv"}>
              <BootstrapTooltip title={meta.linkingDomainsTooltip} placement={"bottom"}>
                <h2 className="moztoolbar-h2 moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                  (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'page'))}>{meta.numberFormat(toolbarData?.pa?.ld, true)}</span>)
                  : blurText('')}</h2>
              </BootstrapTooltip>
              <Typography className="moztoolbar-p moztoolbar-cursor" onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'page'))}>Domains</Typography>
            </div>
            <Divider variant={"middle"} orientation={"vertical"}/>
            <div className={"MuiDividerDiv"}>
              <BootstrapTooltip title={meta.inboundLinksTooltip} placement={"bottom"}>
                <h2 className="moztoolbar-h2 moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                  (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'page'))}>{meta.numberFormat(toolbarData?.pa?.tl, true)}</span>)
                  : blurText('')}</h2>
              </BootstrapTooltip>
              <Typography className="moztoolbar-p moztoolbar-cursor" onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'page'))}>Links</Typography>
            </div>
            <Divider variant={"middle"} orientation={"vertical"}/>
            <div className={"MuiDividerDiv"}>
              <BootstrapTooltip title={meta.keywordsTooltip} placement={"bottom"}>
                <h2 className="moztoolbar-h2 moztoolbar-highlight">{visibility() === VisibilityLevel.Pro ?
                  (<span onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'page'))}>{meta.numberFormat(toolbarData?.pa?.rk, true)}</span>)
                  : blurText('')}</h2>
              </BootstrapTooltip>
              <Typography className="moztoolbar-p moztoolbar-cursor" onClick={(ev) => meta.openContentLink(meta.buildMetricsLink(currentUrl(), 'page'))}>Keywords</Typography>
            </div>

            <div style={{marginLeft: "30px"}}>
              <BootstrapTooltip title={meta.brandAuthorityTooltip} placement={"top"} arrow>
                <Stack alignItems="center" direction="row" spacing={1}>
                  <h1 className="moztoolbar-h1">BA</h1>
                  {visibility() === VisibilityLevel.Pro ? buildPie(20, toolbarData?.brand_authority, undefined,true) : <></>}
                </Stack>
              </BootstrapTooltip>
            </div>
          </Stack>

          {toolbarRightButtons()}
        </Stack>
      </div>
    )
  }
}

export default Toolbar;